"use client";

import { useCallback, useRef, useState } from "react";

const DEEPGRAM_API_KEY = process.env.NEXT_PUBLIC_DEEPGRAM_API_KEY || "";
const DEEPGRAM_WS_URL =
  "wss://api.deepgram.com/v1/listen?" +
  "model=nova-2&smart_format=true&interim_results=true" +
  "&vad_events=true&utterance_end_ms=1500" +
  "&encoding=linear16&sample_rate=16000";

export interface UseDeepgramSTTReturn {
  isListening: boolean;
  transcript: string;
  interimTranscript: string;
  startListening: () => void;
  stopListening: () => void;
}

export function useDeepgramSTT(): UseDeepgramSTTReturn {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState("");
  const [interimTranscript, setInterimTranscript] = useState("");
  const wsRef = useRef<WebSocket | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const reconnectAttempted = useRef(false);

  const cleanup = useCallback(() => {
    processorRef.current?.disconnect();
    processorRef.current = null;
    audioCtxRef.current?.close().catch(() => {});
    audioCtxRef.current = null;
    streamRef.current?.getTracks().forEach((t) => t.stop());
    streamRef.current = null;
    if (wsRef.current && wsRef.current.readyState <= WebSocket.OPEN) {
      wsRef.current.close();
    }
    wsRef.current = null;
    setIsListening(false);
    setInterimTranscript("");
  }, []);

  const connectWebSocket = useCallback(
    (stream: MediaStream) => {
      if (!DEEPGRAM_API_KEY) {
        console.warn("[DeepgramSTT] No API key configured");
        return;
      }

      const ws = new WebSocket(DEEPGRAM_WS_URL, ["token", DEEPGRAM_API_KEY]);
      wsRef.current = ws;

      ws.onopen = () => {
        setIsListening(true);
        reconnectAttempted.current = false;

        // Set up audio capture: mic → AudioContext → ScriptProcessor → WebSocket
        const audioCtx = new AudioContext({ sampleRate: 16000 });
        audioCtxRef.current = audioCtx;
        const source = audioCtx.createMediaStreamSource(stream);
        const processor = audioCtx.createScriptProcessor(4096, 1, 1);
        processorRef.current = processor;

        processor.onaudioprocess = (e) => {
          if (ws.readyState !== WebSocket.OPEN) return;
          const float32 = e.inputBuffer.getChannelData(0);
          // Convert Float32 PCM to Int16 PCM
          const int16 = new Int16Array(float32.length);
          for (let i = 0; i < float32.length; i++) {
            const s = Math.max(-1, Math.min(1, float32[i]));
            int16[i] = s < 0 ? s * 0x8000 : s * 0x7fff;
          }
          ws.send(int16.buffer);
        };

        source.connect(processor);
        processor.connect(audioCtx.destination);
      };

      ws.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data);

          // Handle utterance end — clear interim
          if (data.type === "UtteranceEnd") {
            setInterimTranscript("");
            return;
          }

          const alt = data.channel?.alternatives?.[0];
          if (!alt) return;

          const text = alt.transcript;
          if (!text) return;

          if (data.is_final) {
            setTranscript(text);
            setInterimTranscript("");
          } else {
            setInterimTranscript(text);
          }
        } catch {
          // Ignore non-JSON messages
        }
      };

      ws.onclose = () => {
        // Attempt one reconnect
        if (!reconnectAttempted.current && streamRef.current) {
          reconnectAttempted.current = true;
          setTimeout(() => {
            if (streamRef.current) {
              connectWebSocket(streamRef.current);
            }
          }, 1000);
        } else {
          setIsListening(false);
        }
      };

      ws.onerror = () => {
        ws.close();
      };
    },
    [cleanup],
  );

  const startListening = useCallback(async () => {
    if (wsRef.current) return;
    reconnectAttempted.current = false;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;
      connectWebSocket(stream);
    } catch (err) {
      console.error("[DeepgramSTT] Failed to get audio stream:", err);
    }
  }, [connectWebSocket]);

  const stopListening = useCallback(() => {
    cleanup();
  }, [cleanup]);

  return { isListening, transcript, interimTranscript, startListening, stopListening };
}

