                style={{
                  color: "#fff",
                  fontSize: "0.75rem",
                  whiteSpace: "nowrap",
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                }}
              >
                {item.title}
              </div>
              <div
                style={{
                  color: "#fff",
                  fontSize: "0.85rem",
                  fontWeight: 700,
                  marginTop: 2,
                }}
              >
                {item.price}
              </div>
              <div
                style={{
                  color: "rgba(255,255,255,0.5)",
                  fontSize: "0.65rem",
