     1→"use client";
     2→
     3→import { useCallback, useEffect, useRef, useState } from "react";
     4→import { useSearchParams } from "next/navigation";
     5→import { useCamera } from "@/hooks/useCamera";
     6→import { useGestureRecognizer } from "@/hooks/useGestureRecognizer";
     7→import { useHeyGenAvatar } from "@/hooks/useHeyGenAvatar";
     8→import { useDeepgramSTT } from "@/hooks/useDeepgramSTT";
     9→import { GestureIndicator } from "@/components/mirror/GestureIndicator";
    10→import AvatarPiP from "@/components/mirror/AvatarPiP";
    11→import VoiceIndicator from "@/components/mirror/VoiceIndicator";
    12→import ProductCarousel, {
    13→  type ProductCard,
    14→} from "@/components/mirror/ProductCarousel";
    15→import { SentenceBuffer } from "@/lib/sentence-buffer";
    16→import { socket } from "@/lib/socket";
    17→import type { DetectedGesture, GestureType } from "@/types/gestures";
    18→
    19→export default function MirrorPage() {
    20→  const searchParams = useSearchParams();
    21→  const userId = searchParams.get("user_id");
    22→  const { videoRef, isReady: isCameraReady, error: cameraError } = useCamera();
    23→
    24→  // Gesture state (existing)
    25→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    26→  const gestureKeyRef = useRef(0);
    27→  const [gestureKey, setGestureKey] = useState(0);
    28→
    29→  // Session state
    30→  const [sessionActive, setSessionActive] = useState(false);
    31→  const [products, setProducts] = useState<ProductCard[]>([]);
    32→
    33→  // Hooks for avatar + voice
    34→  const avatar = useHeyGenAvatar();
    35→  const stt = useDeepgramSTT();
    36→
    37→  // Pending transcripts queue (held while Mira is speaking)
    38→  const pendingTranscriptsRef = useRef<string[]>([]);
    39→
    40→  // Sentence buffer: accumulates mira_speech chunks → calls avatar.speak per sentence
    41→  const sentenceBufferRef = useRef<SentenceBuffer | null>(null);
    42→  useEffect(() => {
    43→    sentenceBufferRef.current = new SentenceBuffer((sentence) => {
    44→      avatar.speak(sentence);
    45→    });
    46→  }, [avatar.speak]);
    47→
    48→  // --------------- Socket connection ---------------
    49→
    50→  useEffect(() => {
    51→    socket.connect();
    52→    if (userId) {
    53→      socket.emit("join_room", { user_id: userId });
    54→    }
    55→    return () => {
    56→      socket.disconnect();
    57→    };
    58→  }, [userId]);
    59→
    60→  // --------------- Snapshot handler (existing) ---------------
    61→
    62→  useEffect(() => {
    63→    const handleSnapshotRequest = () => {
    64→      const video = videoRef.current;
    65→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
    66→
    67→      const canvas = document.createElement("canvas");
    68→      canvas.width = video.videoWidth;
    69→      canvas.height = video.videoHeight;
    70→      const ctx = canvas.getContext("2d");
    71→      if (!ctx) return;
    72→
    73→      ctx.drawImage(video, 0, 0);
    74→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
    75→      const base64 = dataUrl.split(",")[1];
    76→
    77→      socket.emit("mirror_event", {
    78→        type: "snapshot",
    79→        image_base64: base64,
    80→        user_id: userId,
    81→      });
    82→    };
    83→
    84→    socket.on("request_snapshot", handleSnapshotRequest);
    85→    return () => {
    86→      socket.off("request_snapshot", handleSnapshotRequest);
    87→    };
    88→  }, [videoRef, userId]);
    89→
    90→  // --------------- Mira speech streaming ---------------
    91→
    92→  useEffect(() => {
    93→    const handleMiraSpeech = (data: { text: string; is_chunk: boolean }) => {
    94→      if (data.is_chunk) {
    95→        sentenceBufferRef.current?.feed(data.text);
    96→      } else {
    97→        // End of stream — flush any remaining buffered text
    98→        sentenceBufferRef.current?.flush();
    99→      }
   100→    };
   101→
   102→    socket.on("mira_speech", handleMiraSpeech);
   103→    return () => {
   104→      socket.off("mira_speech", handleMiraSpeech);
   105→    };
   106→  }, []);
   107→
   108→  // --------------- Tool results (product carousel) ---------------
   109→
   110→  useEffect(() => {
   111→    const handleToolResult = (data: { type: string; items?: ProductCard[] }) => {
   112→      if (data.type === "clothing_results" && data.items) {
   113→        setProducts(data.items);
   114→      }
   115→    };
   116→
   117→    socket.on("tool_result", handleToolResult);
   118→    return () => {
   119→      socket.off("tool_result", handleToolResult);
   120→    };
   121→  }, []);
   122→
   123→  // --------------- Session lifecycle ---------------
   124→
   125→  useEffect(() => {
   126→    const handleSessionStarted = () => {
   127→      setSessionActive(true);
   128→      avatar.startAvatar();
   129→      stt.startListening();
   130→    };
   131→
   132→    const handleSessionEnded = () => {
   133→      setSessionActive(false);
   134→      setProducts([]);
   135→      avatar.stopAvatar();
   136→      stt.stopListening();
   137→    };
   138→
   139→    // The backend emits start_session acknowledgement via session's first mira_speech.
   140→    // We detect session start when we're in a room and receive the first mira_speech.
   141→    // Actually, let's listen for an explicit signal — when the client triggers start_session,
   142→    // the backend processes it. We listen for `session_active` or use start_session as our signal.
   143→    socket.on("session_active", handleSessionStarted);
   144→    socket.on("session_ended", handleSessionEnded);
   145→
   146→    return () => {
   147→      socket.off("session_active", handleSessionStarted);
   148→      socket.off("session_ended", handleSessionEnded);
   149→    };
   150→  }, [avatar.startAvatar, avatar.stopAvatar, stt.startListening, stt.stopListening]);
   151→
   152→  // Fallback: auto-detect session start from first mira_speech if session_active isn't emitted
   153→  const sessionStartedViaFallback = useRef(false);
   154→  useEffect(() => {
   155→    const handleFirstSpeech = () => {
   156→      if (!sessionActive && !sessionStartedViaFallback.current) {
   157→        sessionStartedViaFallback.current = true;
   158→        setSessionActive(true);
   159→        avatar.startAvatar();
   160→        stt.startListening();
   161→      }
   162→    };
   163→
   164→    socket.on("mira_speech", handleFirstSpeech);
   165→    return () => {
   166→      socket.off("mira_speech", handleFirstSpeech);
   167→      sessionStartedViaFallback.current = false;
   168→    };
   169→  }, [sessionActive, avatar.startAvatar, stt.startListening]);
   170→
   171→  // --------------- Voice transcript → backend ---------------
   172→
   173→  // When a final transcript arrives from Deepgram, either queue or send
   174→  const lastTranscriptRef = useRef("");
   175→  useEffect(() => {
   176→    if (!stt.transcript || stt.transcript === lastTranscriptRef.current) return;
   177→    lastTranscriptRef.current = stt.transcript;
   178→
   179→    if (avatar.isSpeaking) {
   180→      // Queue while Mira is speaking
   181→      pendingTranscriptsRef.current.push(stt.transcript);
   182→    } else {
   183→      // Send immediately
   184→      socket.emit("mirror_event", {
   185→        user_id: userId,
   186→        event: { type: "voice", transcript: stt.transcript },
   187→      });
   188→    }
   189→  }, [stt.transcript, avatar.isSpeaking, userId]);
   190→
   191→  // Flush pending transcripts when avatar stops speaking
   192→  useEffect(() => {
   193→    if (!avatar.isSpeaking && pendingTranscriptsRef.current.length > 0) {
   194→      const combined = pendingTranscriptsRef.current.join(" ");
   195→      pendingTranscriptsRef.current = [];
   196→      socket.emit("mirror_event", {
   197→        user_id: userId,
   198→        event: { type: "voice", transcript: combined },
   199→      });
   200→    }
   201→  }, [avatar.isSpeaking, userId]);
   202→
   203→  // --------------- Gesture handling (dual routing) ---------------
   204→
   205→  const handleGesture = useCallback(
   206→    (gesture: DetectedGesture) => {
   207→      console.log("[Mirror] Gesture detected:", gesture.type, gesture.confidence);
   208→
   209→      setLastGesture(gesture.type);
   210→      gestureKeyRef.current += 1;
   211→      setGestureKey(gestureKeyRef.current);
   212→
   213→      // Frontend: animate carousel card immediately
   214→      if (products.length > 0) {
   215→        const carouselGesture = (
   216→          window as unknown as Record<string, unknown>
   217→        ).__carouselGesture as ((g: GestureType) => void) | undefined;
   218→        carouselGesture?.(gesture.type);
   219→      }
   220→
   221→      // Backend: emit gesture event (async, Mira reacts verbally)
   222→      socket.emit("mirror_event", {
   223→        user_id: userId,
   224→        event: {
   225→          type: "gesture",
   226→          gesture: gesture.type,
   227→          confidence: gesture.confidence,
   228→        },
   229→      });
   230→    },
   231→    [userId, products.length],
   232→  );
   233→
   234→  const { isLoading: isModelLoading, error: modelError } =
   235→    useGestureRecognizer({
   236→      videoRef,
   237→      isVideoReady: isCameraReady,
   238→      onGesture: handleGesture,
   239→    });
   240→
   241→  return (
   242→    <main
   243→      style={{
   244→        position: "relative",
   245→        width: "100vw",
   246→        height: "100vh",
   247→        background: "#000",
   248→        overflow: "hidden",
   249→      }}
   250→    >
   251→      {/* Webcam feed (mirrored) */}
   252→      <video
   253→        ref={videoRef}
   254→        autoPlay
   255→        playsInline
   256→        muted
   257→        style={{
   258→          position: "absolute",
   259→          top: 0,
   260→          left: 0,
   261→          width: "100%",
   262→          height: "100%",
   263→          objectFit: "cover",
   264→          transform: "scaleX(-1)",
   265→        }}
   266→      />
   267→
   268→      {/* HeyGen Avatar PiP (top-right) */}
   269→      {sessionActive && (
   270→        <AvatarPiP videoRef={avatar.videoRef} isReady={avatar.isReady} />
   271→      )}
   272→
   273→      {/* Gesture visual feedback */}
   274→      <GestureIndicator key={gestureKey} gesture={lastGesture} />
   275→
   276→      {/* Product carousel (bottom) */}
   277→      <ProductCarousel
   278→        items={products}
   279→        onGesture={(gesture, item) => {
   280→          console.log("[Mirror] Carousel gesture:", gesture, item.title);
   281→        }}
   282→      />
   283→
   284→      {/* Voice indicator (bottom-left) */}
   285→      {sessionActive && (
   286→        <VoiceIndicator
   287→          isListening={stt.isListening}
   288→          interimTranscript={stt.interimTranscript}
   289→        />
   290→      )}
   291→
   292→      {/* Status indicators */}
   293→      {(cameraError || modelError) && (
   294→        <div
   295→          style={{
   296→            position: "absolute",
   297→            bottom: 20,
   298→            left: 20,
   299→            color: "#f44",
   300→            fontSize: "1rem",
   301→            zIndex: 30,
   302→          }}
   303→        >
   304→          {cameraError && <div>Camera: {cameraError}</div>}
   305→          {modelError && <div>Model: {modelError}</div>}
   306→        </div>
   307→      )}
   308→
   309→      {isModelLoading && (
   310→        <div
   311→          style={{
   312→            position: "absolute",
   313→            top: "50%",
   314→            left: "50%",
   315→            transform: "translate(-50%, -50%)",
   316→            color: "#fff",
   317→            fontSize: "1.5rem",
   318→            zIndex: 30,
   319→          }}
   320→        >
   321→          Loading gesture recognition...
   322→        </div>
   323→      )}
   324→    </main>
   325→  );
   326→}
