     4→import StreamingAvatar, {
     5→  AvatarQuality,
     6→  StreamingEvents,
     7→  TaskType,
     8→} from "@heygen/streaming-avatar";
     9→
    10→const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
    11→// HeyGen default public avatar; override via NEXT_PUBLIC_HEYGEN_AVATAR_ID
    12→const AVATAR_ID =
    13→  process.env.NEXT_PUBLIC_HEYGEN_AVATAR_ID || "default";
    14→
    15→export interface UseHeyGenAvatarReturn {
    16→  isReady: boolean;
    17→  isSpeaking: boolean;
    18→  startAvatar: () => Promise<void>;
    19→  stopAvatar: () => Promise<void>;
    20→  speak: (text: string) => Promise<void>;
    21→  interrupt: () => Promise<void>;
    22→  videoRef: React.RefObject<HTMLVideoElement | null>;
    23→}
    24→
    25→async function fetchToken(): Promise<string> {
    26→  const res = await fetch(`${API_URL}/api/heygen/token`);
    27→  if (!res.ok) throw new Error(`Failed to fetch HeyGen token: ${res.status}`);
    28→  const data = await res.json();
    29→  return data.token;
    30→}
    31→
    32→export function useHeyGenAvatar(): UseHeyGenAvatarReturn {
    33→  const [isReady, setIsReady] = useState(false);
    34→  const [isSpeaking, setIsSpeaking] = useState(false);
    35→  const videoRef = useRef<HTMLVideoElement | null>(null);
    36→  const avatarRef = useRef<StreamingAvatar | null>(null);
    37→
    38→  // Cleanup on unmount
    39→  useEffect(() => {
    40→    return () => {
    41→      avatarRef.current?.stopAvatar();
    42→      avatarRef.current = null;
    43→    };
    44→  }, []);
    45→
    46→  const startAvatar = useCallback(async () => {
    47→    if (avatarRef.current) return;
    48→
    49→    const token = await fetchToken();
    50→    const avatar = new StreamingAvatar({ token });
    51→    avatarRef.current = avatar;
    52→
    53→    avatar.on(StreamingEvents.STREAM_READY, (event: { detail: MediaStream }) => {
    54→      if (videoRef.current && event.detail) {
    55→        videoRef.current.srcObject = event.detail;
    56→        videoRef.current.play().catch(() => {});
    57→      }
    58→      setIsReady(true);
    59→    });
    60→
    61→    avatar.on(StreamingEvents.AVATAR_START_TALKING, () => {
    62→      setIsSpeaking(true);
    63→    });
    64→
    65→    avatar.on(StreamingEvents.AVATAR_STOP_TALKING, () => {
    66→      setIsSpeaking(false);
    67→    });
    68→
    69→    avatar.on(StreamingEvents.STREAM_DISCONNECTED, () => {
    70→      setIsReady(false);
    71→      setIsSpeaking(false);
    72→      avatarRef.current = null;
    73→    });
    74→
    75→    await avatar.createStartAvatar({
    76→      quality: AvatarQuality.Medium,
    77→      avatarName: AVATAR_ID,
    78→    });
    79→  }, []);
    80→
    81→  const stopAvatar = useCallback(async () => {
    82→    if (!avatarRef.current) return;
    83→    await avatarRef.current.stopAvatar();
    84→    avatarRef.current = null;
    85→    setIsReady(false);
    86→    setIsSpeaking(false);
    87→    if (videoRef.current) {
    88→      videoRef.current.srcObject = null;
    89→    }
    90→  }, []);
    91→
    92→  const speak = useCallback(async (text: string) => {
    93→    if (!avatarRef.current || !text.trim()) return;
    94→    await avatarRef.current.speak({
    95→      text,
    96→      taskType: TaskType.REPEAT,
    97→    });
    98→  }, []);
    99→
   100→  const interrupt = useCallback(async () => {
   101→    if (!avatarRef.current) return;
   102→    await avatarRef.current.interrupt();
   103→  }, []);
   104→
   105→  return { isReady, isSpeaking, startAvatar, stopAvatar, speak, interrupt, videoRef };
   106→}
