     3→import { useCallback, useRef, useState } from "react";
     4→
     5→const DEEPGRAM_API_KEY = process.env.NEXT_PUBLIC_DEEPGRAM_API_KEY || "";
     6→const DEEPGRAM_WS_URL =
     7→  "wss://api.deepgram.com/v1/listen?" +
     8→  "model=nova-2&smart_format=true&interim_results=true" +
     9→  "&vad_events=true&utterance_end_ms=1500" +
    10→  "&encoding=linear16&sample_rate=16000";
    11→
    12→export interface UseDeepgramSTTReturn {
    13→  isListening: boolean;
    14→  transcript: string;
    15→  interimTranscript: string;
    16→  startListening: () => void;
    17→  stopListening: () => void;
    18→}
    19→
    20→export function useDeepgramSTT(): UseDeepgramSTTReturn {
    21→  const [isListening, setIsListening] = useState(false);
    22→  const [transcript, setTranscript] = useState("");
    23→  const [interimTranscript, setInterimTranscript] = useState("");
    24→  const wsRef = useRef<WebSocket | null>(null);
    25→  const streamRef = useRef<MediaStream | null>(null);
    26→  const audioCtxRef = useRef<AudioContext | null>(null);
    27→  const processorRef = useRef<ScriptProcessorNode | null>(null);
    28→  const reconnectAttempted = useRef(false);
    29→
    30→  const cleanup = useCallback(() => {
    31→    processorRef.current?.disconnect();
    32→    processorRef.current = null;
    33→    audioCtxRef.current?.close().catch(() => {});
    34→    audioCtxRef.current = null;
    35→    streamRef.current?.getTracks().forEach((t) => t.stop());
    36→    streamRef.current = null;
    37→    if (wsRef.current && wsRef.current.readyState <= WebSocket.OPEN) {
    38→      wsRef.current.close();
    39→    }
    40→    wsRef.current = null;
    41→    setIsListening(false);
    42→    setInterimTranscript("");
    43→  }, []);
    44→
    45→  const connectWebSocket = useCallback(
    46→    (stream: MediaStream) => {
    47→      if (!DEEPGRAM_API_KEY) {
    48→        console.warn("[DeepgramSTT] No API key configured");
    49→        return;
    50→      }
    51→
    52→      const ws = new WebSocket(DEEPGRAM_WS_URL, ["token", DEEPGRAM_API_KEY]);
    53→      wsRef.current = ws;
    54→
    55→      ws.onopen = () => {
    56→        setIsListening(true);
    57→        reconnectAttempted.current = false;
    58→
    59→        // Set up audio capture: mic → AudioContext → ScriptProcessor → WebSocket
    60→        const audioCtx = new AudioContext({ sampleRate: 16000 });
    61→        audioCtxRef.current = audioCtx;
    62→        const source = audioCtx.createMediaStreamSource(stream);
    63→        const processor = audioCtx.createScriptProcessor(4096, 1, 1);
    64→        processorRef.current = processor;
    65→
    66→        processor.onaudioprocess = (e) => {
    67→          if (ws.readyState !== WebSocket.OPEN) return;
    68→          const float32 = e.inputBuffer.getChannelData(0);
    69→          // Convert Float32 PCM to Int16 PCM
    70→          const int16 = new Int16Array(float32.length);
    71→          for (let i = 0; i < float32.length; i++) {
    72→            const s = Math.max(-1, Math.min(1, float32[i]));
    73→            int16[i] = s < 0 ? s * 0x8000 : s * 0x7fff;
    74→          }
    75→          ws.send(int16.buffer);
    76→        };
    77→
    78→        source.connect(processor);
    79→        processor.connect(audioCtx.destination);
    80→      };
    81→
    82→      ws.onmessage = (event) => {
    83→        try {
    84→          const data = JSON.parse(event.data);
    85→
    86→          // Handle utterance end — clear interim
    87→          if (data.type === "UtteranceEnd") {
    88→            setInterimTranscript("");
    89→            return;
    90→          }
    91→
    92→          const alt = data.channel?.alternatives?.[0];
    93→          if (!alt) return;
    94→
    95→          const text = alt.transcript;
    96→          if (!text) return;
    97→
    98→          if (data.is_final) {
    99→            setTranscript(text);
   100→            setInterimTranscript("");
   101→          } else {
   102→            setInterimTranscript(text);
   103→          }
   104→        } catch {
   105→          // Ignore non-JSON messages
   106→        }
   107→      };
   108→
   109→      ws.onclose = () => {
   110→        // Attempt one reconnect
   111→        if (!reconnectAttempted.current && streamRef.current) {
   112→          reconnectAttempted.current = true;
   113→          setTimeout(() => {
   114→            if (streamRef.current) {
   115→              connectWebSocket(streamRef.current);
   116→            }
   117→          }, 1000);
   118→        } else {
   119→          setIsListening(false);
   120→        }
   121→      };
   122→
   123→      ws.onerror = () => {
   124→        ws.close();
   125→      };
   126→    },
   127→    [cleanup],
   128→  );
   129→
   130→  const startListening = useCallback(async () => {
   131→    if (wsRef.current) return;
   132→    reconnectAttempted.current = false;
   133→
   134→    try {
   135→      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
   136→      streamRef.current = stream;
   137→      connectWebSocket(stream);
   138→    } catch (err) {
   139→      console.error("[DeepgramSTT] Failed to get audio stream:", err);
   140→    }
   141→  }, [connectWebSocket]);
   142→
   143→  const stopListening = useCallback(() => {
   144→    cleanup();
   145→  }, [cleanup]);
   146→
   147→  return { isListening, transcript, interimTranscript, startListening, stopListening };
   148→}
